import { useState, useMemo, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  Search, ShieldCheck, Shield, ShieldAlert, ShieldX, Loader2, AlertTriangle, ArrowUpRight,
  TrendingUp, Trophy, Skull, ArrowUp, ArrowDown, BarChart3, ChevronDown, Sparkles,
} from "lucide-react";
import { motion } from "framer-motion";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { useMarket } from "@/lib/MarketContext";
import { Reveal } from "@/components/landing/motion";
import { MarkupHistogram, ReputationMix, WorstOffenders, BlacklistSpotlight, MarkupScatter } from "@/components/landing/SellerCharts";

const sellerDetailPath = (name) => `/sellers/${encodeURIComponent(name)}`;

const LABEL_STYLES = {
  Trustworthy: { icon: ShieldCheck, color: "text-emerald-400", bg: "bg-emerald-500/10", border: "border-emerald-500/40" },
  Neutral: { icon: Shield, color: "text-zinc-400", bg: "bg-white/[0.04]", border: "border-white/10" },
  Suspicious: { icon: ShieldAlert, color: "text-amber-400", bg: "bg-amber-500/10", border: "border-amber-500/40" },
  Flagged: { icon: ShieldX, color: "text-red-400", bg: "bg-red-500/10", border: "border-red-500/40" },
};

const PAGE_SIZE = 24;
const SORTS = [
  { id: "listings",    key: "totalListings",    label: "Most listings", Icon: TrendingUp },
  { id: "name",        key: null,               label: "Name (A–Z)",    Icon: TrendingUp },
  { id: "markup",      key: "avgMarkupPercent", label: "Avg markup",    Icon: TrendingUp },
  { id: "overpriced",  key: "overpricedRatio",  label: "Overpriced %", Icon: TrendingUp },
];

export default function SellersPage() {
  const { sellers, loading, error } = useMarket();
  const navigate = useNavigate();
  const [q, setQ] = useState("");
  const [labelFilter, setLabelFilter] = useState("");
  const [sortId, setSortId] = useState("listings");
  const [sortDir, setSortDir] = useState("desc");
  const [page, setPage] = useState(1);
  const [showNerdStats, setShowNerdStats] = useState(() => {
    try { return localStorage.getItem("castia.nerdStats") === "1"; } catch { return false; }
  });
  useEffect(() => {
    try { localStorage.setItem("castia.nerdStats", showNerdStats ? "1" : "0"); } catch { /* ignore */ }
  }, [showNerdStats]);

  const safeSellers = useMemo(() => sellers || [], [sellers]);

  const filtered = useMemo(() => {
    const query = q.trim().toLowerCase();
    return safeSellers.filter((s) => {
      if (query && !s.name.toLowerCase().includes(query)) return false;
      if (labelFilter && s.accuracyLabel !== labelFilter) return false;
      return true;
    });
  }, [safeSellers, q, labelFilter]);

  const sorted = useMemo(() => {
    const sortDef = SORTS.find((s) => s.id === sortId) || SORTS[0];
    const out = [...filtered];
    const dir = sortDir === "asc" ? 1 : -1;
    out.sort((a, b) => {
      if (sortId === "name" || sortDef.key === null) return a.name.localeCompare(b.name) * dir;
      const av = a[sortDef.key] ?? 0;
      const bv = b[sortDef.key] ?? 0;
      return (av - bv) * dir;
    });
    return out;
  }, [filtered, sortId, sortDir]);

  const stats = useMemo(() => ({
    total: safeSellers.length,
    trust: safeSellers.filter((s) => s.accuracyLabel === "Trustworthy").length,
    susp: safeSellers.filter((s) => s.accuracyLabel === "Suspicious").length,
    flagged: safeSellers.filter((s) => s.accuracyLabel === "Flagged" || s.isBlacklisted).length,
    avgMarkup: safeSellers.length > 0
      ? safeSellers.reduce((s, x) => s + (x.avgMarkupPercent || 0), 0) / safeSellers.length
      : 0,
  }), [safeSellers]);

  // Podium: top 3 cheapest, top 3 most expensive. Excludes blacklisted.
  const podium = useMemo(() => {
    const eligible = safeSellers.filter((s) => !s.isBlacklisted && s.totalListings > 0);
    const cheapest = [...eligible].sort((a, b) => a.avgMarkupPercent - b.avgMarkupPercent).slice(0, 3);
    const priciest = [...eligible].sort((a, b) => b.avgMarkupPercent - a.avgMarkupPercent).slice(0, 3);
    return { cheapest, priciest };
  }, [safeSellers]);

  // Pagination
  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));
  const safePage = Math.min(page, totalPages);
  const start = (safePage - 1) * PAGE_SIZE;
  const visible = sorted.slice(start, start + PAGE_SIZE);

  const flipSort = (id) => {
    if (sortId === id) setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    else { setSortId(id); setSortDir("desc"); }
    setPage(1);
  };

  return (
    <div data-testid="sellers-page" className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-amber-400 mb-4">/ Seller Reputation</div>
            <h1 className="font-heading text-5xl sm:text-6xl lg:text-7xl tracking-tighter font-black leading-[0.95]">
              Who you're<br /><span className="text-amber-400">buying from</span>.
            </h1>
            <p className="mt-6 text-zinc-400 max-w-2xl text-lg">
              Every auction-house seller, ranked by listing accuracy. Tap a card to see their reputation breakdown.
            </p>
          </Reveal>

          <Reveal delay={0.1} className="mt-12">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-px bg-white/10 border border-white/10 rounded-lg overflow-hidden">
              {[
                { l: "Total sellers", v: stats.total, c: "text-white" },
                { l: "Trustworthy", v: stats.trust, c: "text-emerald-400" },
                { l: "Suspicious", v: stats.susp, c: "text-amber-400" },
                { l: "Flagged", v: stats.flagged, c: "text-red-400" },
              ].map((s) => (
                <div key={s.l} data-testid={`sellers-stat-${s.l.toLowerCase().replace(/\s+/g, "-")}`} className="bg-bg-base/80 px-6 py-5">
                  <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">{s.l}</div>
                  <div className={`font-heading font-extrabold text-2xl tabular ${s.c}`}>{loading.sellers ? "—" : s.v}</div>
                </div>
              ))}
            </div>
          </Reveal>

          {/* Podium: top 3 cheapest and top 3 priciest non-flagged sellers */}
          {!loading.sellers && podium.cheapest.length > 0 && (
            <Reveal delay={0.15} className="mt-8 grid lg:grid-cols-2 gap-4">
              <PodiumCard
                title="Cheapest sellers"
                sub="Lowest avg markup vs. median — most likely to underprice"
                icon={Trophy}
                accent="emerald"
                sellers={podium.cheapest}
                onSellerClick={(name) => navigate(sellerDetailPath(name))}
                metric={(s) => `${s.avgMarkupPercent > 0 ? "+" : ""}${s.avgMarkupPercent.toFixed(1)}%`}
                metricLabel="markup"
                metricIsGood={(s) => s.avgMarkupPercent < 0}
              />
              <PodiumCard
                title="Priciest sellers"
                sub="Highest avg markup vs. median — most likely to overprice"
                icon={Skull}
                accent="red"
                sellers={podium.priciest}
                onSellerClick={(name) => navigate(sellerDetailPath(name))}
                metric={(s) => `${s.avgMarkupPercent > 0 ? "+" : ""}${s.avgMarkupPercent.toFixed(1)}%`}
                metricLabel="markup"
                metricIsGood={(s) => s.avgMarkupPercent < 0}
              />
            </Reveal>
          )}

          {/* Data viz: markup distribution, reputation mix, worst offenders, scatter, blacklist */}
          {!loading.sellers && safeSellers.length > 0 && (
            <div className="mt-10">
              <button
                type="button"
                data-testid="sellers-nerd-toggle"
                onClick={() => setShowNerdStats((s) => !s)}
                aria-expanded={showNerdStats}
                className={`w-full flex items-center justify-between gap-3 border border-dashed rounded-2xl px-5 py-4 transition-colors group text-left ${
                  showNerdStats
                    ? "border-amber-500/40 bg-amber-500/[0.04] hover:bg-amber-500/[0.06]"
                    : "border-white/15 hover:border-amber-500/40 hover:bg-white/[0.02]"
                }`}
              >
                <div className="flex items-center gap-3 min-w-0">
                  <div className="relative shrink-0">
                    <div className="absolute inset-0 bg-amber-500/20 blur-md rounded-full opacity-0 group-hover:opacity-100 transition-opacity" />
                    <Sparkles className="relative w-5 h-5 text-amber-400" />
                  </div>
                  <div className="min-w-0">
                    <div className="font-heading text-sm font-bold text-white">Stats for nerds</div>
                    <div className="font-mono text-[10px] text-zinc-500 uppercase tracking-wider truncate">
                      5 charts · distribution, mix, offenders, scatter, blacklist
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  <span className="font-mono text-[10px] text-zinc-500 uppercase tracking-wider hidden sm:inline">
                    {showNerdStats ? "Hide" : "Show"}
                  </span>
                  <ChevronDown
                    className={`w-4 h-4 text-zinc-400 transition-transform duration-300 ${showNerdStats ? "rotate-180 text-amber-400" : ""}`}
                  />
                </div>
              </button>

              {showNerdStats && (
                <Reveal className="mt-4 space-y-4">
                  <div className="grid lg:grid-cols-3 gap-4">
                    <div className="lg:col-span-2 bg-bg-deep border border-white/10 rounded-2xl p-5" data-testid="markup-histogram">
                      <div className="flex items-center gap-2 mb-1">
                        <BarChart3 className="w-4 h-4 text-amber-400" />
                        <span className="font-mono text-[10px] uppercase tracking-[0.25em] text-amber-400">Markup distribution</span>
                        <span className="ml-auto font-mono text-[10px] text-zinc-500 tabular">{safeSellers.length} sellers</span>
                      </div>
                      <p className="text-zinc-500 text-xs leading-relaxed mb-4">
                        How far sellers price above or below the median. Bars left of <span className="text-emerald-400">0%</span> undercut the market; bars right of <span className="text-red-400">+10%</span> overprice it.
                      </p>
                      <MarkupHistogram sellers={safeSellers} />
                    </div>
                    <div className="bg-bg-deep border border-white/10 rounded-2xl p-5">
                      <div className="flex items-center gap-2 mb-1">
                        <ShieldCheck className="w-4 h-4 text-emerald-400" />
                        <span className="font-mono text-[10px] uppercase tracking-[0.25em] text-emerald-400">Reputation mix</span>
                      </div>
                      <p className="text-zinc-500 text-xs leading-relaxed mb-4">
                        Breakdown by accuracy label.
                      </p>
                      <ReputationMix sellers={safeSellers} />
                    </div>
                  </div>

                  <div className="grid lg:grid-cols-2 gap-4">
                    <WorstOffenders
                      sellers={safeSellers}
                      openSeller={(name) => navigate(sellerDetailPath(name))}
                    />
                    <BlacklistSpotlight
                      sellers={safeSellers}
                      openSeller={(name) => navigate(sellerDetailPath(name))}
                    />
                  </div>

                  <div className="bg-bg-deep border border-white/10 rounded-2xl p-5" data-testid="markup-scatter-card">
                    <div className="flex items-center gap-2 mb-1">
                      <BarChart3 className="w-4 h-4 text-amber-400" />
                      <span className="font-mono text-[10px] uppercase tracking-[0.25em] text-amber-400">Volume vs markup</span>
                      <span className="ml-auto font-mono text-[10px] text-zinc-500 hidden sm:inline">Hover dots for seller details</span>
                    </div>
                    <p className="text-zinc-500 text-xs leading-relaxed mb-4">
                      Each dot is one seller. Right = more listings; up = more markup. Dot size scales with volume. Click a card below to drill in.
                    </p>
                    <div className="min-h-[260px] sm:min-h-0">
                      <MarkupScatter
                        sellers={safeSellers}
                        openSeller={(name) => navigate(sellerDetailPath(name))}
                      />
                    </div>
                  </div>
                </Reveal>
              )}
            </div>
          )}

          <div className="mt-10 flex flex-col lg:flex-row gap-4">
            <div className="relative flex-1 max-w-xl">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
              <input
                data-testid="sellers-search"
                type="text" value={q} onChange={(e) => { setQ(e.target.value); setPage(1); }}
                placeholder="Search sellers…"
                aria-label="Search sellers"
                className="w-full bg-white/[0.03] border border-white/10 focus:border-emerald-500 rounded-lg pl-11 pr-4 py-3 text-white placeholder-zinc-600 outline-none transition-colors"
              />
            </div>
            <select data-testid="filter-label" value={labelFilter} onChange={(e) => { setLabelFilter(e.target.value); setPage(1); }}
              aria-label="Filter by seller rating"
              className="bg-white/[0.03] border border-white/10 focus:border-emerald-500 rounded-lg px-4 py-3 text-white outline-none cursor-pointer font-mono text-xs uppercase tracking-wider">
              <option value="" className="bg-bg-base">All ratings</option>
              <option value="Trustworthy" className="bg-bg-base">Trustworthy</option>
              <option value="Neutral" className="bg-bg-base">Neutral</option>
              <option value="Suspicious" className="bg-bg-base">Suspicious</option>
              <option value="Flagged" className="bg-bg-base">Flagged</option>
            </select>
          </div>

          {/* Active filter chips + sort + clear all */}
          {(q || labelFilter) && (
            <div className="mt-4 flex flex-wrap gap-2 items-center">
              {q && (
                <button onClick={() => { setQ(""); setPage(1); }} className="inline-flex items-center gap-2 bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 rounded-full px-3 py-1.5 font-mono text-[11px] uppercase tracking-wider hover:bg-emerald-500/20 transition-colors">
                  Search: "{q}" <span className="text-emerald-500/70">×</span>
                </button>
              )}
              {labelFilter && (
                <button onClick={() => { setLabelFilter(""); setPage(1); }} className="inline-flex items-center gap-2 bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 rounded-full px-3 py-1.5 font-mono text-[11px] uppercase tracking-wider hover:bg-emerald-500/20 transition-colors">
                  Rating: {labelFilter} <span className="text-emerald-500/70">×</span>
                </button>
              )}
              <button
                onClick={() => { setQ(""); setLabelFilter(""); setPage(1); }}
                data-testid="sellers-clear-all"
                className="inline-flex items-center gap-1.5 border border-white/10 hover:border-red-500/40 hover:text-red-400 text-zinc-400 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-full transition-colors"
              >
                Clear all
              </button>
            </div>
          )}

          {/* Sort + paginator (top) */}
          <div className="mt-4 flex flex-wrap items-center gap-3 font-mono text-[10px] uppercase tracking-wider text-zinc-500">
            <span>Sort ·</span>
            {SORTS.map((s) => {
              const active = sortId === s.id;
              return (
                <button
                  key={s.id}
                  data-testid={`sellers-sort-${s.id}`}
                  onClick={() => flipSort(s.id)}
                  className={`inline-flex items-center gap-1 px-2.5 py-1 rounded border transition-colors ${active ? "border-emerald-500/40 bg-emerald-500/10 text-emerald-300" : "border-white/10 text-zinc-400 hover:text-white"}`}
                >
                  {s.label}
                  {active && (sortDir === "asc" ? <ArrowUp className="w-3 h-3" /> : <ArrowDown className="w-3 h-3" />)}
                </button>
              );
            })}
          </div>

          {!loading.sellers && sorted.length > PAGE_SIZE && (
            <div className="mt-4 flex items-center justify-between px-1 font-mono text-xs">
              <span className="text-zinc-500">Page {safePage} of {totalPages} · <span className="tabular">{sorted.length}</span> sellers</span>
              <div className="flex gap-2">
                <button data-testid="sellers-prev" onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={safePage === 1} className="px-3 py-1.5 border border-white/15 rounded hover:border-emerald-500 hover:text-emerald-400 disabled:opacity-30 disabled:cursor-not-allowed transition-colors">← Prev</button>
                <button data-testid="sellers-next" onClick={() => setPage((p) => Math.min(totalPages, p + 1))} disabled={safePage === totalPages} className="px-3 py-1.5 border border-white/15 rounded hover:border-emerald-500 hover:text-emerald-400 disabled:opacity-30 disabled:cursor-not-allowed transition-colors">Next →</button>
              </div>
            </div>
          )}

          {error.sellers && (
            <div className="mt-6 inline-flex items-center gap-2 bg-amber-500/10 border border-amber-500/30 text-amber-300 rounded-lg px-4 py-2 font-mono text-xs">
              <AlertTriangle className="w-4 h-4" /> {error.sellers}
            </div>
          )}

          <div className="mt-6 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {loading.sellers
              ? Array.from({ length: 6 }).map((_, i) => (<div key={i} className="bg-white/[0.02] border border-white/10 rounded-2xl p-6 h-48 animate-pulse" />))
              : visible.map((s, i) => {
                  const label = s.isBlacklisted ? "Flagged" : (s.accuracyLabel || "Neutral");
                  const style = LABEL_STYLES[label] || LABEL_STYLES.Neutral;
                  const Icon = style.icon;
                  const markup = s.avgMarkupPercent;
                  const isBedrock = s.identityKey?.startsWith("bedrock");
                  return (
                    <motion.button
                      key={s.key}
                      data-testid={`seller-card-${i}`}
                      initial={{ opacity: 0, y: 14 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: Math.min(i * 0.012, 0.35), duration: 0.5, ease: [0.16, 1, 0.3, 1] }}
                      whileHover={{ y: -4, transition: { duration: 0.2 } }}
                      onClick={() => navigate(sellerDetailPath(s.name))}
                      className={`group relative bg-white/[0.02] border ${style.border} rounded-2xl p-4 sm:p-6 hover:border-white/40 transition-all text-left w-full min-w-0 overflow-hidden`}
                    >
                      <div className="flex items-start gap-3 sm:gap-4 mb-5">
                        <div className="relative shrink-0">
                          {!isBedrock ? (
                            <img
                              src={`https://render.crafty.gg/3d/bust/${encodeURIComponent(s.name)}`}
                              alt={`${s.name} avatar`}
                              width={64} height={64} loading="lazy"
                              className="w-12 h-12 sm:w-16 sm:h-16 rounded-lg bg-white/[0.04] object-contain transition-transform group-hover:scale-105"
                              onError={(e) => { e.currentTarget.style.display = "none"; e.currentTarget.nextSibling.style.display = "grid"; }}
                            />
                          ) : null}
                          <div className="w-12 h-12 sm:w-16 sm:h-16 rounded-lg bg-white/[0.04] border border-white/10 place-items-center text-zinc-500 font-mono text-xs uppercase"
                            style={{ display: isBedrock ? "grid" : "none" }}>
                            {s.name.slice(0, 2).toUpperCase()}
                          </div>
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="font-heading text-base sm:text-lg font-bold tracking-tight truncate group-hover:text-emerald-400 transition-colors">{s.name}</div>
                          <div className="font-mono text-[10px] text-zinc-500 truncate">{isBedrock ? "Bedrock" : s.uuid ? `Java · ${s.uuid.slice(0, 8)}` : "—"}</div>
                          <div className={`mt-2 inline-flex items-center gap-1.5 ${style.bg} ${style.border} border rounded-full px-2 py-0.5`}>
                            <Icon className={`w-2.5 h-2.5 ${style.color}`} />
                            <span className={`font-mono text-[9px] uppercase tracking-wider ${style.color}`}>{label}</span>
                          </div>
                        </div>
                        <ArrowUpRight className="w-4 h-4 text-zinc-600 group-hover:text-emerald-400 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-all shrink-0" />
                      </div>

                      <div className="grid grid-cols-3 gap-2 sm:gap-3 pt-4 border-t border-white/5">
                        <Stat label="Listings" value={s.totalListings} />
                        <Stat label="Markup" value={`${markup > 0 ? "+" : ""}${markup.toFixed(1)}%`} color={markup > 15 ? "text-red-400" : markup < -10 ? "text-emerald-400" : "text-white"} />
                        <Stat label="Overpriced" value={`${s.overpricedRatio.toFixed(1)}%`} />
                      </div>
                    </motion.button>
                  );
                })}
          </div>

          {/* Bottom paginator */}
          {!loading.sellers && sorted.length > PAGE_SIZE && (
            <div className="mt-8 flex items-center justify-between px-1 font-mono text-xs">
              <span className="text-zinc-500">Page {safePage} of {totalPages} · <span className="tabular">{sorted.length}</span> sellers</span>
              <div className="flex gap-2">
                <button onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={safePage === 1} className="px-3 py-1.5 border border-white/15 rounded hover:border-emerald-500 hover:text-emerald-400 disabled:opacity-30 disabled:cursor-not-allowed transition-colors">← Prev</button>
                <button onClick={() => setPage((p) => Math.min(totalPages, p + 1))} disabled={safePage === totalPages} className="px-3 py-1.5 border border-white/15 rounded hover:border-emerald-500 hover:text-emerald-400 disabled:opacity-30 disabled:cursor-not-allowed transition-colors">Next →</button>
              </div>
            </div>
          )}

          {!loading.sellers && sorted.length === 0 && (
            <div className="mt-10 text-center text-zinc-500 font-mono text-xs uppercase tracking-wider py-16">No sellers match your filters.</div>
          )}
          {loading.sellers && (
            <div className="mt-6 inline-flex items-center gap-2 text-zinc-500 font-mono text-xs"><Loader2 className="w-3.5 h-3.5 animate-spin" /> Loading…</div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
}

function Stat({ label, value, color = "text-white" }) {
  return (
    <div>
      <div className="font-mono text-[9px] uppercase tracking-wider text-zinc-500">{label}</div>
      <div className={`font-heading font-bold tabular ${color}`}>{value}</div>
    </div>
  );
}

function PodiumCard({ title, sub, icon: Icon, accent, sellers, onSellerClick, metric, metricIsGood }) {
  const accentMap = {
    emerald: { text: "text-emerald-400", bg: "bg-emerald-500/10", border: "border-emerald-500/30" },
    red:     { text: "text-red-400",     bg: "bg-red-500/10",     border: "border-red-500/30" },
  };
  const a = accentMap[accent];
  return (
    <div className={`bg-bg-deep border ${a.border} rounded-2xl p-5`}>
      <div className="flex items-center gap-2 mb-1">
        <Icon className={`w-4 h-4 ${a.text}`} />
        <span className={`font-mono text-[10px] uppercase tracking-[0.25em] ${a.text}`}>{title}</span>
      </div>
      <p className="text-zinc-500 text-xs leading-relaxed mb-4">{sub}</p>
      <div className="space-y-2">
        {sellers.map((s, i) => {
          const label = s.isBlacklisted ? "Flagged" : (s.accuracyLabel || "Neutral");
          const isGood = metricIsGood(s);
          return (
            <button
              key={s.key}
              data-testid={`podium-${accent}-${i}`}
              onClick={() => onSellerClick(s.name)}
              className="w-full flex items-center gap-3 bg-white/[0.02] border border-white/5 hover:border-white/20 rounded-lg p-2.5 transition-colors text-left group"
            >
              <span className="font-heading text-2xl font-black text-zinc-600 group-hover:text-white w-6 tabular text-center">
                {i + 1}
              </span>
              <div className="flex-1 min-w-0">
                <div className="font-heading text-sm font-bold truncate group-hover:text-emerald-400 transition-colors">{s.name}</div>
                <div className="font-mono text-[10px] text-zinc-500 uppercase tracking-wider">{s.totalListings} listings · {label}</div>
              </div>
              <div className={`font-mono text-sm font-bold tabular ${isGood ? "text-emerald-400" : "text-red-400"}`}>
                {metric(s)}
              </div>
            </button>
          );
        })}
      </div>
    </div>
  );
}